<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('communications.view');if($_SERVER['REQUEST_METHOD']!=='POST'||!validarTokenCsrf((string)($_POST['csrf_token']??''))){http_response_code(400);exit;}$pdo=obtenerConexion();$accion=(string)($_POST['accion']??'');$rid=cmsId($_POST['reporte_id']??0);$uid=cmsId($_POST['usuario_id']??0);try{$pdo->beginTransaction();if(in_array($accion,['moderar','descartar','bloquear'],true)){$q=$pdo->prepare('SELECT r.*,m.remitente_id FROM chat_reportes r JOIN chat_mensajes m ON m.id=r.mensaje_id WHERE r.id=:id FOR UPDATE');$q->execute(['id'=>$rid]);$r=$q->fetch();if(!$r)throw new DomainException('Reporte no encontrado.');if($accion==='moderar'){$pdo->prepare("UPDATE chat_mensajes SET estado='moderado' WHERE id=:id")->execute(['id'=>$r['mensaje_id']]);$estado='moderado';}elseif($accion==='descartar')$estado='descartado';else{$pdo->prepare("INSERT INTO chat_bloqueos(usuario_id,bloqueado_por,motivo) VALUES(:u,:a,'Bloqueo por moderación') ON DUPLICATE KEY UPDATE bloqueado_por=:a2,motivo='Bloqueo por moderación',bloqueado_at=NOW(),desbloqueado_at=NULL")->execute(['u'=>$r['remitente_id'],'a'=>$_SESSION['usuario_id'],'a2'=>$_SESSION['usuario_id']]);$estado='revisado';}$pdo->prepare('UPDATE chat_reportes SET estado=:e,revisado_por=:u,revisado_at=NOW() WHERE id=:id')->execute(['e'=>$estado,'u'=>$_SESSION['usuario_id'],'id'=>$rid]);}elseif($accion==='desbloquear'){$pdo->prepare('UPDATE chat_bloqueos SET desbloqueado_at=NOW() WHERE usuario_id=:u')->execute(['u'=>$uid]);}else throw new DomainException('Acción inválida.');registrarAuditoria(['event_type'=>'chat.moderation','module'=>'communications','entity_type'=>'chat_report','entity_id'=>$rid?:$uid,'action'=>$accion,'description'=>'Acción administrativa de moderación.'],$pdo);$pdo->commit();cmsFlash('success','Moderación actualizada.');}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();cmsFlash('danger',$e instanceof DomainException?$e->getMessage():'No fue posible moderar.');}header('Location:moderacion.php');
